#!/usr/bin/env bash
set -euo pipefail

mode="source"
if [[ "${1:-}" == "--mode" ]]; then
  mode="${2:-source}"
  shift 2
elif [[ "${1:-}" == --mode=* ]]; then
  mode="${1#--mode=}"
  shift
fi
case "$mode" in
  source|live-runtime) ;;
  *) printf 'usage: %s [--mode source|live-runtime] [root]\n' "$0" >&2; exit 2 ;;
esac

root="${1:-.}"

fail() {
  printf 'restart hardening validation failed: %s\n' "$*" >&2
  exit 1
}

need_file() {
  local path="$root/$1"
  [[ -f "$path" ]] || fail "missing $1"
}

need_grep() {
  local pattern="$1"
  local file="$2"
  grep -Eq "$pattern" "$root/$file" || fail "$file does not match required pattern: $pattern"
}

reject_grep() {
  local pattern="$1"
  local file="$2"
  [[ -f "$root/$file" ]] || return 0
  if grep -Eq "$pattern" "$root/$file"; then
    fail "$file still matches rejected pattern: $pattern"
  fi
}

reject_host_reboot_automation() {
  local pattern='systemctl[[:space:]][^;&|]*\breboot\b|shutdown[[:space:]]+(-r|now)|(^|[[:space:]])(/sbin/|/bin/)?reboot[[:space:]]+(-f|--force)|(^|[[:space:]])poweroff([[:space:]]|$)|(^|[[:space:]])kexec([[:space:]]|$)'
  local path
  while IFS= read -r path; do
    if grep -Eq "$pattern" "$path"; then
      fail "${path#$root/} contains host reboot/shutdown automation; reboot testing must remain operator-controlled"
    fi
  done < <(
    find "$root/ops" "$root/scripts" "$root/host" "$root/docker" "$root/.github" \
      -type f \
      ! -path '*/runtime/*' \
      ! -path '*/__pycache__/*' \
      ! -name '*.pyc' \
      2>/dev/null
  )
}

validate_runtime_compose() {
  need_file "docker-compose.yml"
  if [[ "$mode" != "live-runtime" ]]; then
    return 0
  fi
  need_grep '^# BDAG_GENERATED_PI5_RUNTIME_COMPOSE=1$' "docker-compose.yml"
  reject_grep '^[[:space:]]*(build|dockerfile):' "docker-compose.yml"
  reject_grep 'container_name:' "docker-compose.yml"
  need_grep '^[[:space:]]+postgres:' "docker-compose.yml"
  need_grep '^[[:space:]]+node:' "docker-compose.yml"
  need_grep '^[[:space:]]+pool:' "docker-compose.yml"
}

